import type { IconDefinition, PopupManager } from "../../../index";
type Separator = {
    separator: true;
};
type Item = {
    icon?: IconDefinition;
    label: string;
    warning?: boolean;
    disabled?: boolean;
    chevron?: boolean;
};
type ResolverItem = Item & {
    resolveWith: any;
};
type OnclickItem = Item & {
    onclick: (event: MouseEvent, manager: PopupManager) => void;
};
type SubmenuItem = Item & {
    submenu: ContextMenuItemConfig[];
};
export type ContextMenuItemConfig = Separator | ResolverItem | OnclickItem | SubmenuItem;
export type ContextMenuItemConfigAny = Separator & ResolverItem & OnclickItem & SubmenuItem;
export {};
